from sys import stdin
from itertools import permutations

def main():
    n = stdin.readline().rstrip()
    if int(n) % 2 == 0:
        print(n)
    else:
        for perm in permutations(n, 2):
            if int(perm[0] + n[1:]) % 2 == 0:
                print(perm[0] + n[1:])
                return
        print(-1)

if __name__ == '__main__':
    main()
